import React, { useEffect, useState, useCallback } from "react";
import { Modal, Input, Button, Space, Tag } from "antd";
import { useDispatch, useSelector } from "react-redux";
import {
  getNotApprovedProducts,
  updateProductStatus,
} from "../../features/product/productSlice";
import { toast, ToastContainer } from "react-toastify";
import "react-toastify/dist/ReactToastify.css";
import {
  ShieldCheck,
  XCircle,
  Clock,
  Package,
  AlertTriangle,
  CheckCircle2,
  RefreshCw,
  Eye,
  Zap,
} from "lucide-react";

const { TextArea } = Input;

const NotApprovedProductList = () => {
  const dispatch = useDispatch();
  const [openRejectModal, setOpenRejectModal] = useState(false);
  const [selectedProductId, setSelectedProductId] = useState(null);
  const [rejectionReason, setRejectionReason] = useState("");
  const [suggestedChanges, setSuggestedChanges] = useState("");
  const [approvingId, setApprovingId] = useState(null);
  const [lastUpdated, setLastUpdated] = useState(new Date());
  const [isRefreshing, setIsRefreshing] = useState(false);

  const products = useSelector(
    (state) => state?.product?.pendingProducts || []
  );
  const isLoading = useSelector((state) => state?.product?.isLoading);

  const fetchProducts = useCallback(() => {
    dispatch(getNotApprovedProducts());
    setLastUpdated(new Date());
  }, [dispatch]);

  useEffect(() => {
    fetchProducts();
    // Real-time polling every 15 seconds
    const interval = setInterval(() => {
      fetchProducts();
    }, 15000);
    return () => clearInterval(interval);
  }, [fetchProducts]);

  const handleManualRefresh = async () => {
    setIsRefreshing(true);
    fetchProducts();
    setTimeout(() => setIsRefreshing(false), 800);
  };

  const handleApprove = async (productId) => {
    setApprovingId(productId);
    try {
      await dispatch(
        updateProductStatus({ productId, ProductApproved: "Approved" })
      ).unwrap();
      toast.success("✅ Product approved and is now live!", {
        position: "top-right",
        autoClose: 3000,
        style: { borderLeft: "4px solid #10b981" },
      });
      fetchProducts();
    } catch {
      toast.error("Failed to approve product", { position: "top-right" });
    } finally {
      setApprovingId(null);
    }
  };

  const handleReject = (productId) => {
    setSelectedProductId(productId);
    setOpenRejectModal(true);
    setRejectionReason("");
    setSuggestedChanges("");
  };

  const handleRejectSubmit = async () => {
    if (!rejectionReason.trim()) {
      toast.error("Violation reason is required.");
      return;
    }
    const payload = {
      productId: selectedProductId,
      ProductApproved: "Rejected",
      rejectionReason: {
        Reason: rejectionReason,
        Suggested_Changes: suggestedChanges || "None",
        Rejection_Date: new Date().toISOString().split("T")[0],
      },
    };
    try {
      await dispatch(updateProductStatus(payload)).unwrap();
      toast.success("Compliance report filed.", {
        style: { borderLeft: "4px solid #ef4444" },
      });
      setOpenRejectModal(false);
      fetchProducts();
    } catch {
      toast.error("Failed to file report.");
    }
  };

  const getProductImage = (product) => {
    const imgData = product?.images || product?.image;
    if (Array.isArray(imgData) && imgData.length > 0)
      return imgData[0]?.secure_url || imgData[0];
    if (imgData?.secure_url) return imgData.secure_url;
    const cImg = product?.colors?.[0]?.images;
    if (Array.isArray(cImg) && cImg.length > 0)
      return cImg[0]?.secure_url || cImg[0];
    return `https://api.dicebear.com/7.x/shapes/svg?seed=${product?.title}`;
  };

  const timeSince = (date) => {
    const seconds = Math.floor((new Date() - date) / 1000);
    if (seconds < 60) return `${seconds}s ago`;
    const minutes = Math.floor(seconds / 60);
    if (minutes < 60) return `${minutes}m ago`;
    return `${Math.floor(minutes / 60)}h ago`;
  };

  return (
    <div style={{ padding: "0", minHeight: "100vh" }}>
      {/* Header */}
      <div
        style={{
          background: "linear-gradient(135deg, #0f172a 0%, #1e3a8a 50%, #0f172a 100%)",
          borderRadius: "28px",
          padding: "40px 48px",
          marginBottom: "32px",
          position: "relative",
          overflow: "hidden",
        }}
      >
        {/* Background decorations */}
        <div style={{
          position: "absolute", top: -60, right: -60, width: 200, height: 200,
          background: "rgba(59,130,246,0.15)", borderRadius: "50%", filter: "blur(40px)"
        }} />
        <div style={{
          position: "absolute", bottom: -40, left: 200, width: 150, height: 150,
          background: "rgba(16,185,129,0.1)", borderRadius: "50%", filter: "blur(30px)"
        }} />

        <div style={{ position: "relative", zIndex: 1, display: "flex", justifyContent: "space-between", alignItems: "flex-start", flexWrap: "wrap", gap: 20 }}>
          <div>
            <div style={{ display: "flex", alignItems: "center", gap: 12, marginBottom: 8 }}>
              <div style={{
                width: 44, height: 44, background: "rgba(16,185,129,0.2)",
                borderRadius: 14, display: "flex", alignItems: "center",
                justifyContent: "center", border: "1px solid rgba(16,185,129,0.3)"
              }}>
                <ShieldCheck size={22} color="#10b981" />
              </div>
              <div>
                <p style={{ margin: 0, fontSize: 11, fontWeight: 800, color: "#64748b", textTransform: "uppercase", letterSpacing: "0.2em" }}>
                  SuperAdmin Console
                </p>
                <h1 style={{ margin: 0, fontSize: 28, fontWeight: 900, color: "#fff", letterSpacing: "-0.02em" }}>
                  Compliance Review Queue
                </h1>
              </div>
            </div>
            <p style={{ margin: 0, color: "#94a3b8", fontSize: 14, fontWeight: 500 }}>
              Review, approve or reject merchant product submissions before they go live.
            </p>
          </div>

          <div style={{ display: "flex", alignItems: "center", gap: 16 }}>
            {/* Live indicator */}
            <div style={{
              display: "flex", alignItems: "center", gap: 8,
              background: "rgba(16,185,129,0.1)", border: "1px solid rgba(16,185,129,0.2)",
              padding: "8px 16px", borderRadius: 12
            }}>
              <div style={{
                width: 8, height: 8, borderRadius: "50%", background: "#10b981",
                animation: "pulse 2s infinite", boxShadow: "0 0 0 0 rgba(16,185,129,0.4)"
              }} />
              <span style={{ fontSize: 12, fontWeight: 700, color: "#10b981", textTransform: "uppercase", letterSpacing: "0.1em" }}>
                Live · {timeSince(lastUpdated)}
              </span>
            </div>

            {/* Refresh button */}
            <button
              onClick={handleManualRefresh}
              style={{
                display: "flex", alignItems: "center", gap: 8,
                background: "rgba(255,255,255,0.1)", border: "1px solid rgba(255,255,255,0.15)",
                color: "#fff", padding: "8px 18px", borderRadius: 12,
                cursor: "pointer", fontSize: 13, fontWeight: 700,
                transition: "all 0.2s"
              }}
            >
              <RefreshCw size={14} style={{ animation: isRefreshing ? "spin 0.8s linear infinite" : "none" }} />
              Refresh
            </button>

            {/* Count badge */}
            <div style={{
              background: "rgba(245,158,11,0.15)", border: "1px solid rgba(245,158,11,0.3)",
              padding: "12px 24px", borderRadius: 16, textAlign: "center"
            }}>
              <p style={{ margin: 0, fontSize: 10, fontWeight: 800, color: "#f59e0b", textTransform: "uppercase", letterSpacing: "0.2em" }}>
                Awaiting Review
              </p>
              <p style={{ margin: 0, fontSize: 32, fontWeight: 900, color: "#fbbf24", lineHeight: 1.2 }}>
                {products.length}
              </p>
            </div>
          </div>
        </div>
      </div>

      {/* Content */}
      {isLoading && products.length === 0 ? (
        <div style={{ display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", padding: "80px 0", gap: 20 }}>
          <div style={{ width: 60, height: 60, borderRadius: "50%", border: "3px solid #e2e8f0", borderTopColor: "#2563eb", animation: "spin 0.8s linear infinite" }} />
          <p style={{ color: "#94a3b8", fontSize: 15, fontWeight: 600 }}>Loading compliance queue…</p>
        </div>
      ) : products.length === 0 ? (
        /* Empty State */
        <div style={{
          background: "#fff", borderRadius: 24, border: "1px solid #e2e8f0",
          padding: "80px 40px", textAlign: "center", boxShadow: "0 4px 24px rgba(0,0,0,0.04)"
        }}>
          <div style={{ width: 80, height: 80, background: "#f0fdf4", borderRadius: "50%", display: "flex", alignItems: "center", justifyContent: "center", margin: "0 auto 24px", border: "2px solid #86efac" }}>
            <CheckCircle2 size={36} color="#22c55e" />
          </div>
          <h2 style={{ margin: "0 0 8px", fontSize: 22, fontWeight: 900, color: "#0f172a" }}>All Clear!</h2>
          <p style={{ margin: 0, color: "#64748b", fontSize: 15 }}>No products are waiting for compliance review. The queue is empty.</p>
        </div>
      ) : (
        /* Product Cards */
        <div style={{ display: "flex", flexDirection: "column", gap: 16 }}>
          {products.map((product, index) => (
            <div
              key={product._id || product.id}
              style={{
                background: "#fff",
                borderRadius: 20,
                border: "1px solid #e2e8f0",
                padding: "24px 28px",
                display: "flex",
                alignItems: "center",
                gap: 20,
                boxShadow: "0 2px 12px rgba(0,0,0,0.04)",
                transition: "all 0.2s",
                animation: `fadeInUp 0.3s ease ${index * 0.05}s both`,
              }}
            >
              {/* Image */}
              <div style={{
                width: 72, height: 72, borderRadius: 16, overflow: "hidden",
                flexShrink: 0, border: "2px solid #f1f5f9", background: "#f8fafc"
              }}>
                <img
                  src={getProductImage(product)}
                  alt={product.title}
                  style={{ width: "100%", height: "100%", objectFit: "cover" }}
                  onError={(e) => { e.target.src = `https://api.dicebear.com/7.x/shapes/svg?seed=${product.title}`; }}
                />
              </div>

              {/* Product info */}
              <div style={{ flex: 1, minWidth: 0 }}>
                <div style={{ display: "flex", alignItems: "center", gap: 10, marginBottom: 6 }}>
                  <h3 style={{ margin: 0, fontSize: 16, fontWeight: 800, color: "#0f172a", whiteSpace: "nowrap", overflow: "hidden", textOverflow: "ellipsis", maxWidth: 320 }}>
                    {product.title}
                  </h3>
                  <span style={{
                    background: "#fef3c7", color: "#92400e", border: "1px solid #fde68a",
                    padding: "2px 10px", borderRadius: 20, fontSize: 10, fontWeight: 800,
                    textTransform: "uppercase", letterSpacing: "0.05em", flexShrink: 0
                  }}>
                    Pending
                  </span>
                </div>
                <div style={{ display: "flex", gap: 16, flexWrap: "wrap" }}>
                  <span style={{ fontSize: 13, color: "#64748b", fontWeight: 600 }}>
                    <span style={{ color: "#94a3b8" }}>Category: </span>{product.category}
                  </span>
                  <span style={{ fontSize: 13, color: "#64748b", fontWeight: 600 }}>
                    <span style={{ color: "#94a3b8" }}>Brand: </span>{product.brand || "—"}
                  </span>
                  <span style={{ fontSize: 13, color: "#64748b", fontWeight: 600 }}>
                    <span style={{ color: "#94a3b8" }}>Price: </span>
                    <b style={{ color: "#0f172a" }}>{Number(product.price).toLocaleString()} ETB</b>
                  </span>
                  <span style={{ fontSize: 13, color: "#64748b", fontWeight: 600 }}>
                    <span style={{ color: "#94a3b8" }}>Stock: </span>
                    <span style={{ color: product.quantity > 0 ? "#16a34a" : "#dc2626" }}>{product.quantity} units</span>
                  </span>
                </div>
              </div>

              {/* Store info */}
              <div style={{
                background: "#f8fafc", border: "1px solid #e2e8f0", borderRadius: 12,
                padding: "8px 16px", textAlign: "center", flexShrink: 0
              }}>
                <p style={{ margin: 0, fontSize: 10, fontWeight: 700, color: "#94a3b8", textTransform: "uppercase", letterSpacing: "0.1em" }}>Store</p>
                <p style={{ margin: 0, fontSize: 13, fontWeight: 700, color: "#1e293b", maxWidth: 120, whiteSpace: "nowrap", overflow: "hidden", textOverflow: "ellipsis" }}>
                  {product.store?.storeName || "Direct"}
                </p>
              </div>

              {/* Actions */}
              <div style={{ display: "flex", gap: 10, flexShrink: 0 }}>
                <button
                  onClick={() => handleApprove(product._id || product.id)}
                  disabled={approvingId === (product._id || product.id)}
                  style={{
                    display: "flex", alignItems: "center", gap: 6,
                    background: approvingId === (product._id || product.id) ? "#d1fae5" : "linear-gradient(135deg, #059669, #10b981)",
                    color: approvingId === (product._id || product.id) ? "#059669" : "#fff",
                    border: "none", padding: "10px 20px", borderRadius: 12,
                    cursor: "pointer", fontSize: 13, fontWeight: 700,
                    transition: "all 0.2s", boxShadow: "0 4px 12px rgba(16,185,129,0.25)",
                  }}
                >
                  {approvingId === (product._id || product.id) ? (
                    <><RefreshCw size={14} style={{ animation: "spin 0.6s linear infinite" }} /> Approving…</>
                  ) : (
                    <><ShieldCheck size={14} /> Approve</>
                  )}
                </button>
                <button
                  onClick={() => handleReject(product._id || product.id)}
                  style={{
                    display: "flex", alignItems: "center", gap: 6,
                    background: "#fff", color: "#ef4444",
                    border: "2px solid #fecaca", padding: "10px 20px", borderRadius: 12,
                    cursor: "pointer", fontSize: 13, fontWeight: 700, transition: "all 0.2s",
                  }}
                >
                  <XCircle size={14} /> Reject
                </button>
              </div>
            </div>
          ))}
        </div>
      )}

      {/* Reject Modal */}
      <Modal
        title={
          <div style={{ display: "flex", alignItems: "center", gap: 10, paddingBottom: 12, borderBottom: "1px solid #fee2e2" }}>
            <div style={{ width: 36, height: 36, background: "#fef2f2", borderRadius: 10, display: "flex", alignItems: "center", justifyContent: "center" }}>
              <AlertTriangle size={18} color="#ef4444" />
            </div>
            <div>
              <p style={{ margin: 0, fontSize: 11, fontWeight: 800, color: "#ef4444", textTransform: "uppercase", letterSpacing: "0.1em" }}>Compliance Violation</p>
              <p style={{ margin: 0, fontSize: 16, fontWeight: 900, color: "#0f172a" }}>File Rejection Report</p>
            </div>
          </div>
        }
        open={openRejectModal}
        onOk={handleRejectSubmit}
        onCancel={() => setOpenRejectModal(false)}
        okText="File Report & Reject"
        cancelText="Cancel"
        okButtonProps={{ danger: true, style: { borderRadius: 10, fontWeight: 700, height: 40 } }}
        cancelButtonProps={{ style: { borderRadius: 10, height: 40 } }}
        width={560}
        styles={{ body: { padding: "24px 0 8px" } }}
      >
        <div style={{ display: "flex", flexDirection: "column", gap: 20 }}>
          <div>
            <label style={{ fontSize: 11, fontWeight: 800, color: "#64748b", textTransform: "uppercase", letterSpacing: "0.1em", display: "block", marginBottom: 8 }}>
              Primary Violation Reason *
            </label>
            <TextArea
              rows={3}
              value={rejectionReason}
              onChange={(e) => setRejectionReason(e.target.value)}
              placeholder="Describe the specific policy violation (e.g., missing images, incorrect pricing, restricted category)…"
              style={{ borderRadius: 12, fontSize: 14 }}
            />
          </div>
          <div>
            <label style={{ fontSize: 11, fontWeight: 800, color: "#64748b", textTransform: "uppercase", letterSpacing: "0.1em", display: "block", marginBottom: 8 }}>
              Recommended Fixes (Optional)
            </label>
            <TextArea
              rows={3}
              value={suggestedChanges}
              onChange={(e) => setSuggestedChanges(e.target.value)}
              placeholder="What should the merchant fix to comply with platform standards?"
              style={{ borderRadius: 12, fontSize: 14 }}
            />
          </div>
          <div style={{ background: "#fef3c7", border: "1px solid #fde68a", borderRadius: 12, padding: "12px 16px", display: "flex", gap: 8 }}>
            <AlertTriangle size={16} color="#d97706" style={{ flexShrink: 0, marginTop: 1 }} />
            <p style={{ margin: 0, fontSize: 12, color: "#92400e", fontWeight: 600, lineHeight: 1.5 }}>
              The merchant will be notified and their product will be hidden from the public catalog.
            </p>
          </div>
        </div>
      </Modal>

      <ToastContainer />

      <style>{`
        @keyframes fadeInUp {
          from { opacity: 0; transform: translateY(16px); }
          to { opacity: 1; transform: translateY(0); }
        }
        @keyframes spin {
          from { transform: rotate(0deg); }
          to { transform: rotate(360deg); }
        }
        @keyframes pulse {
          0% { box-shadow: 0 0 0 0 rgba(16,185,129,0.4); }
          70% { box-shadow: 0 0 0 8px rgba(16,185,129,0); }
          100% { box-shadow: 0 0 0 0 rgba(16,185,129,0); }
        }
      `}</style>
    </div>
  );
};

export default NotApprovedProductList;
